/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Autorizações"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedLibCliCod.IsEmpty() print printBlockFilterPedLibCliCod EndIf If not &PedLibSolFun.IsEmpty() print printBlockFilterPedLibSolFun EndIf If not &PedLibSts.IsEmpty() &FilterPedLibStsValueDescription = &PedLibSts.EnumerationDescription()
print printBlockFilterPedLibSts EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PEDLIBSOLDTA' &PedLibSolDta1.FromString(&GridStateDynamicFilter.Value) If not &PedLibSolDta1.IsEmpty() &PedLibSolDta = &PedLibSolDta1 print printBlockFilterPedLibSolDta EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PEDLIBSOLDTA' &PedLibSolDta2.FromString(&GridStateDynamicFilter.Value) If not &PedLibSolDta2.IsEmpty() &PedLibSolDta = &PedLibSolDta2 print printBlockFilterPedLibSolDta EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PEDLIBSOLDTA' &PedLibSolDta3.FromString(&GridStateDynamicFilter.Value) If not &PedLibSolDta3.IsEmpty() &PedLibSolDta = &PedLibSolDta3 print printBlockFilterPedLibSolDta EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedLibSolDta) when &OrderedBy = 1 order PedCod when &OrderedBy = 2 AND &OrderedDsc = False order (PedCod) when &OrderedBy = 2 AND &OrderedDsc = True order PedLibItm when &OrderedBy = 3 AND &OrderedDsc = False order (PedLibItm) when &OrderedBy = 3 AND &OrderedDsc = True order PedLibSolDta when &OrderedBy = 4 AND &OrderedDsc = False order (PedLibSolDta) when &OrderedBy = 4 AND &OrderedDsc = True order PedLibObs when &OrderedBy = 5 AND &OrderedDsc = False order (PedLibObs) when &OrderedBy = 5 AND &OrderedDsc = True order PedLibSolFun when &OrderedBy = 6 AND &OrderedDsc = False order (PedLibSolFun) when &OrderedBy = 6 AND &OrderedDsc = True
using DSwpLiberacaoPedidos(&PedCod, &PedLibCliCod, &PedLibSolFun, &DynamicFiltersSelector1, &PedLibSolDta1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &PedLibSolDta2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PedLibSolDta3, &PedLibSts) &PedLibStsDescription = PedLibSts.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wpLiberacaoPedidosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wpLiberacaoPedidosGridState")) Else &GridState.FromXml(&Session.Get(!"wpLiberacaoPedidosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDLIBCLICOD" &PedLibCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDLIBSOLFUN" &PedLibSolFun.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDLIBSTS" &PedLibSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

Output_file("ExportReportwpLiberacaoPedidos","PDF");

